import {
    PIE_CHARTNAME,
    SUNBURST_CHARTNAME,
    PACKEDBUBBLE_CHARTNAME,
    TREEMAP_CHARTNAME,
    AREA_CHARTNAME,
    LINE_CHARTNAME
} from '../../core/chartname-constants';
import { d3_select } from '../../core/d3-constants';
import { defined } from '../../utils/zcutils';
import { STYLE_SELECTOR } from '../../axis/tickFilter/node-selection-mapping';
import { charttype, charttypenames } from '../../core/main-zc-init';

export function setPivotAttributes(elements, chartObj, chartName) {
    let _rawData = getRawData(chartName);

    if (chartObj.dataObject.pivot) {
        elements
            //
            .attr('levelbycolumn', d => _rawData(d).levelByColumn)
            .attr('levelbyrow', d => _rawData(d).levelByRow);
    }
}

function getRawData(chartName, labelData) {
    if (chartName === SUNBURST_CHARTNAME || chartName === PACKEDBUBBLE_CHARTNAME || chartName === TREEMAP_CHARTNAME) {
        return getLeafData;
    } else if (chartName === PIE_CHARTNAME) {
        return d => d.data;
    } else if (chartName === AREA_CHARTNAME || chartName === LINE_CHARTNAME) {
        return d => d[0] && d[0];
    } else if (chartName == 'label') {
        return labelData ? (labelData, i) => labelData[labelData.length - 1 - i] : d => d.data || d;
    } else {
        return d => d;
    }
}

function getLeafData(d) {
    // Parent data doesn't have levelByRow, levelByColumn info ZC2734
    if (d.children) {
        return getLeafData(d.children[0]);
    } else {
        return d.data;
    }
}

export function setOpacityForTickFilterElements(elements, chartObj, chartName, labelData) {
    if (chartObj.dataObject.hierarchical && chartObj.cache.hierarchical) {
        let _rawData = getRawData(chartName, labelData);
        elements.style('opacity', function(d, i) {
            let opacity = getOpacityForTickFilterElements(d, i, chartObj, chartName, labelData);
            d3_select(this).attr('filtered-opacity', opacity);
            return opacity;
        });
    }
}

export function _setOpacityForTickFilterElements(d, i, chartObj, chartName) {
    if (chartObj.dataObject.hierarchical && chartObj.cache.hierarchical) {
        let opacity = getOpacityForTickFilterElements(d, i, chartObj, chartName);
        return opacity;
    }
}

export function getOpacityForTickFilterElements(d, i, chartObj, chartName, labelData){
    let _rawData = getRawData(chartName, labelData);

    var tickFilterCache = chartObj.cache.hierarchical,
        cacheRow = tickFilterCache.row,
        cacheColumn = tickFilterCache.column,
        isRowActive = true,
        isColumnActive = true,
        d1 = _rawData(labelData || d, i);

    if (cacheRow && cacheRow.active) {
        var query = cacheRow.query;
        isRowActive = defined(d1.levelByRow) ? d1.levelByRow.startsWith(query) : true;
    }
    if (cacheColumn && cacheColumn.active) {
        var query = cacheColumn.query;
        isColumnActive = defined(d1.levelByColumn) ? d1.levelByColumn.startsWith(query) : true;
    }
    var styleSelector = STYLE_SELECTOR.get(chartName),
        propertyName = (styleSelector && styleSelector[1]) || 'opacity',
        propertyValue = chartObj.systemConf.chart.plot.plotoptions[chartName]
            ? chartObj.systemConf.chart.plot.plotoptions[chartName][propertyName]
            : 1;
    let opacity = isRowActive && isColumnActive ? propertyValue : 0.1;

    return opacity;
}
